module.exports=[14940,a=>{"use strict";a.s(["post",0,{id:"note-mots-cles-intention",title:"Mot-clé ≠ intention. Et c'est là que tout se joue.",excerpt:"Chercher un mot-clé sans comprendre l'intention, c'est comme crier dans le vide.",category:"seo",type:"visual-note",date:"2025-02-18",readTime:"2 min",content:[{type:"paragraph",text:"Un mot-clé est une suite de mots. L'intention est la raison derrière ces mots. Ce n'est pas la même chose, et les confondre est l'une des erreurs les plus coûteuses en SEO."},{type:"paragraph",text:"Quelqu'un qui cherche 'stratégie de contenu SEO' veut peut-être comprendre ce que c'est, embaucher quelqu'un pour le faire, comparer des outils, ou trouver un modèle. Même mot-clé. Quatre intentions complètement différentes. Si vous rédigez un article informatif ciblant une intention transactionnelle, vous vous positionnerez pour la mauvaise audience et ne convertirez personne."},{type:"paragraph",text:"Avant d'écrire un seul mot, posez-vous la question : que veut vraiment cette personne quand elle tape cette requête ? Cherche-t-elle à apprendre quelque chose, à faire quelque chose, à trouver quelque chose ou à acheter quelque chose ? La réponse détermine tout : le format, le ton, l'appel à l'action et la structure de la page."},{type:"paragraph",text:"Les mots-clés vous font entrer dans la pièce. L'intention vous permet de conclure."}]}])}];

